package com.hospital.management.validation;import com.hospital.management.model.*;import java.time.*;import java.util.*;
/** Validates prescription headers and indexed medicine rows. */public class PrescriptionValidator {private static final Set<String>S=Set.of("ACTIVE","COMPLETED","CANCELLED");public ValidationResult validate(PrescriptionForm f){ValidationResult r=new ValidationResult();if(f==null){r.addError("form","Prescription details are required");return r;}if(f.getMedicalRecordId()==null||f.getMedicalRecordId()<=0)r.addError("medicalRecordId","Valid medical record is required");if(f.getNotes()!=null&&f.getNotes().length()>2000)r.addError("notes","Notes must not exceed 2000 characters");String status=f.getStatus()==null||f.getStatus().isBlank()?"ACTIVE":f.getStatus().toUpperCase(Locale.ROOT);if(!S.contains(status))r.addError("status","Invalid prescription status");if(f.getValidUntil()!=null&&!f.getValidUntil().isBlank())try{LocalDate d=LocalDate.parse(f.getValidUntil());LocalDate now=LocalDate.now();if(d.isBefore(now)||d.isAfter(now.plusYears(1)))r.addError("validUntil","Validity must be today through one year from today");}catch(Exception e){r.addError("validUntil","Enter date as yyyy-MM-dd");}List<PrescriptionItemForm>x=f.getItems();if(x==null||x.isEmpty())r.addError("items","Add at least one medicine");else if(x.size()>20)r.addError("items","Maximum 20 medicines are allowed");if(x!=null)for(int i=0;i<x.size();i++){PrescriptionItemForm a=x.get(i);req(a==null?null:a.getMedicineName(),"items["+i+"].medicineName",2,200,r);req(a==null?null:a.getDosage(),"items["+i+"].dosage",1,100,r);req(a==null?null:a.getFrequency(),"items["+i+"].frequency",1,100,r);req(a==null?null:a.getDuration(),"items["+i+"].duration",1,100,r);max(a==null?null:a.getRoute(),"items["+i+"].route",100,r);max(a==null?null:a.getInstructions(),"items["+i+"].instructions",500,r);}return r;}private void req(String v,String k,int min,int max,ValidationResult r){int n=v==null?0:v.trim().length();if(n<min||n>max)r.addError(k,"Must contain "+min+"-"+max+" characters");}private void max(String v,String k,int max,ValidationResult r){if(v!=null&&v.length()>max)r.addError(k,"Must not exceed "+max+" characters");}}
